<template>
    <div class="app-header-search" v-on-clickaway="clickOutside">
        <form class="form-search" @submit.stop.prevent="onSubmit()">
            <div class="form-search-input">
                <input type="text"  v-model.trim="form.keyword" @keydown="onKeyDown" ref="input"  class="form-control">
            </div>
            <div class="form-search-dropdown">
                <div class="form-group-select">
                    <label for="header_search_collection">{{selectedCollection}}</label>
                    <select @change="onChange()" v-model="form.collection_id">
                        <option value="all">All Collections</option>
                        <option v-for="(item , index) in collections" :key="`collection_${index}`" :value="item.id">{{item.title}}</option>
                    </select>
                </div>
            </div>
            <div class="form-search-action">
                <button class="btn btn-warning">
                    <i class="fas fa-search"></i>
                </button>
            </div>
        </form>
        <div class="app-header-search-result" v-if="products.length && $route.name != 'Search'">
            <div class="search-body">
                <transition-group name="fade-transform" mode="out-in" class="list-products">
                    <div class="item" v-for="(item , index) in products" :key="`product_${index}`" @click="selectItem(index)" :class="{ 'is-selected' : index == activeItemIndex}">
                        <a class="item-image">
                            <img v-if="item.image" :src="item.image" alt="">
                            <img v-else src="@/assets/images/default/product.png" alt="">
                        </a>
                        <div class="item-content">
                            <div class="item-title" :title="item.title">
                                {{item.title}}
                            </div>
                            <div class="item-supplier">
                                <span>By</span>
                                <a>{{item.shop_name}}</a>
                            </div>
                            <div class="item-price">
                                <span>
                                    <template v-if="item.price_min != item.price_max">
                                        {{ item.price_min | number_format }}$ - {{ item.price_max | number_format}}$
                                    </template>
                                    <template v-else>
                                        {{ item.price_max | number_format}}$
                                    </template>
                                </span>
                            </div>
                        </div>

                    </div>
                </transition-group>
            </div>
            <div class="search-foot">
                <button class="btn btn-link">
                    View all results
                </button>
            </div>
        </div>
    </div>
</template>
<script>
import {mapGetters} from 'vuex'
import { setTimeout } from 'timers';
export default {
    name : 'HeaderSearch',
    data(){
        return {
            form :{
                keyword : '',
                collection_id : 'all'
            },
            loading : false,
            products : [],
            activeItemIndex: -1,
            timeout : null
        }
    },
    computed:{
        ...mapGetters({
            collections : '$_Home/getCollections'
        }),
        selectedCollection(){
            if( this.form.collection_id == 'all'){
                return 'All Collections'
            }else{
                var item = _.find(this.collections , { id : this.form.collection_id})
                return item == undefined ? '' : item.title
            }
        }
    },
    methods:{
        selectCollection(item){
            this.selected = 'Collection  Collection' + item;
        },
        onSubmit(){
            this.products = []
            this.redirect({
                name : 'Search',
                query : {
                    keyword : this.form.keyword,
                    collection_id : this.form.collection_id
                }
            })
        },
        loadListProduct(){
            if( this.loading ) return;
            this.loading = true
            this.$store.dispatch('SEARCH_PRODUCT_HEADER' , this.form ).then((res)=>{
                this.loading = false
                let { status , data , is_more } = res
                if( status ){
                    this.is_more = is_more
                    this.products = data
                }
            })
        },
        clickOutside(){
            if( this.products.length ){
                this.products = []
            }
        },
        onKeyDown(e){
            switch (e.keyCode) {
				case 40:
					this.highlightItem('down')
					e.preventDefault()
					break
				case 38:
					this.highlightItem('up')
					e.preventDefault()
					break
                case 13:
                    if( this.activeItemIndex >= 0){
                        this.selectItem(this.activeItemIndex)
                    }else{
                        this.onSubmit()
                    }
					e.preventDefault()
					break
				case 27:
					this.showItems = false
					e.preventDefault()
					break
				default:
					return true
			}
        },
        highlightItem(direction) {
			if (this.products.length === 0) {
				return
			}
			let selectedIndex = this.products.findIndex((item, index) => {
				return index === this.activeItemIndex
			})
			if (selectedIndex === -1) {
				if (direction === 'down') {
					selectedIndex = 0
				} else {
					selectedIndex = this.products.length - 1
				}
			} else {
				this.activeIndexItem = 0
				if (direction === 'down') {
					selectedIndex++
					if (selectedIndex === this.products.length) {
						selectedIndex = 0
					}
				} else {
					selectedIndex--
					if (selectedIndex < 0) {
						selectedIndex = this.products.length - 1
					}
				}
			}
			this.activeItemIndex = selectedIndex
		},
		selectItem(index) {
            if( this.products.length > index){
                this.redirect({
                    name : 'ProductDetail',
                    params :{
                        id : `${this.products[index].handle}-${this.products[index].id}`
                    }
                })
                this.products = []
                this.$refs.input.blur()
            }
        },
        onChange(){
            if( this.$route.name== 'Search'){
                this.onSubmit()
            }
        }
    },
    watch : {
        products : function(value){
            this.activeItemIndex = -1
        },
    },
    created(){
        if( this.$route.name == 'Search'){
            var collection_id = this.$route.query.collection_id ? this.$route.query.collection_id : null
            if( collection_id ){
                var item = _.find(this.collections , { id : collection_id })
                if( item ){
                    this.form.collection_id = collection_id
                }
            }
            this.form.keyword = this.$route.query.keyword ? this.$route.query.keyword : ''
        }
    },
    mounted(){
        this.$watch('form.keyword' , (value)=>{
            this.products = []
            if( value.length >= 2  && this.$route.name != 'Search'){
                this.loadListProduct();
            }else{
                this.products = []
            }
        })
    },
}
</script>

<style lang="scss" scoped>
    @import 'src/assets/scss/static/variables';
    .app-header-search{
        width: 100%;
        padding-top: 10px;
        position: relative;
        .form-search{
            min-height: 50px;
            display: flex;
            flex-wrap: nowrap;
            flex-direction: row;
            &-input{
                width: calc(100% - 250px);
                background: #fff;
                border-bottom-left-radius: 25px;
                border-top-left-radius: 25px;
                overflow: hidden;
                display: block;
                position: relative;
                padding: 6px 15px;
                .form-control{
                    border-radius: 0;
                    border: none;
                    padding: 0 ;
                    line-height: 36px;
                    &:focus{
                        outline: none;
                        box-shadow: none;
                    }
                }
                &:after{
                    content: '';
                    position: absolute;
                    top: 20%;
                    right: 0;
                    width: 2px;
                    bottom: 20%;
                    background: $yellow;
                }
            }
            &-dropdown{
                white-space: nowrap;
                background: #fff;
                padding: 6px 0px;
                line-height: 36px;
                height: auto;
                text-overflow: ellipsis;
                width: 175px;
                .form-group-select{
                    padding: 0 10px;
                    label{
                        color:$text-color;
                        margin: 0;
                        padding-right: 5px;
                        max-width: 150px;
                        overflow: hidden;
                        display: block;
                        white-space: nowrap;
                        text-overflow: ellipsis;
                    }
                    select{
                        opacity: 0;
                        position: absolute;
                        width: 100%;
                        right: 0;
                        left: 0;
                        top: 0;
                    }
                }
            }
            &-action{
                width: 75px;
                border-bottom-right-radius: 25px;
                border-top-right-radius: 25px;
                overflow: hidden;
                background: #fff;
                button{
                    color:#fff;
                    display: flex;
                    height: 100%;
                    width: 100%;
                    align-items: center;
                    justify-content: center;
                    border-radius: 0;
                    padding: 0;
                    font-size: 20px;
                    &:hover{
                        color:#fff;
                    }
                }
            }
        }
        &-result{
            background: #fff;
            border: 1px solid #ccc;
            box-shadow: 0 5px 10px rgba(0,0,0,0.19), 0 3px 3px rgba(0,0,0,0.23);
            margin-top: 15px;
            border-radius: 10px;
            width: 100%;
            transition: all 0.3s ease;
            overflow: hidden auto;
            position: absolute;
            top:100%;
            left: 0;
            right: 0;
            z-index: 100;
            color:$text-color;
            &.is-active{
                opacity: 1;
                visibility: visible;
                transform: none;
            }
            .search{
                &-head{
                    padding: 20px 30px;
                    box-shadow:  0 0 6px #ccc;
                    strong{
                        font-size: 16px;
                        text-transform: uppercase;
                        font-weight: 500;
                    }
                }
                &-body{
                    padding: 5px 10px;
                    .list-products{
                        .item{
                            padding: 10px 30px;
                            display: flex;
                            flex-direction: row;
                            flex-wrap: wrap;
                            &.is-selected{
                                background: #ccc;
                            }
                            &-image{
                                width: 70px;
                                height: 70px;
                                overflow: hidden;
                                display: flex;
                                align-items: center;
                                justify-content: center;
                                img{
                                    max-width: 100%;
                                    max-height: 100%;
                                    width: 100%;
                                    border-radius: 10px;
                                    border: 3px solid transparent;
                                }
                                &:hover{
                                    img{
                                        border-color: $yellow;
                                    }
                                }
                            }
                            &-title{
                                color:$text-color;
                                font-size: 14px;
                                font-weight: 500;
                                // text-transform: uppercase;
                                white-space: nowrap;
                                text-overflow: ellipsis;
                                overflow: hidden;
                                display: block;
                                text-decoration: none;
                                &:hover{
                                    color:$yellow;
                                    text-decoration: underline;
                                }
                            }
                            &-supplier{
                                font-size: 12px;
                                span{
                                    display: inline-block;
                                    margin-right: 5px;
                                }
                                a{
                                    color:$yellow;
                                    font-weight: 500;
                                    text-decoration: none;
                                    &:hover{
                                        text-decoration: underline;
                                    }
                                }
                            }
                            &-content{
                                width: calc(100% - 70px);
                                // padding: 0px 15px;
                                padding-left: 15px;
                            }
                            &-price{
                                width: 100%;
                                display: flex;
                                flex-direction: row;
                                align-items: center;
                                justify-content: flex-start;
                                span{
                                    // padding: 6px 15px;
                                    // background: #F2F2F2;
                                    // display: inline-block;
                                    // border-radius: 21px;
                                    font-size: 20px;
                                    font-weight: 500;
                                }
                            }
                        }
                    }
                }
                &-foot{
                    text-align: center;
                    padding: 5px 15px;
                    button{
                        color: $yellow;
                    }
                }
            }
        }
    }
    .search {

        &-leave-active,
        &-enter-active {
            transition: all .5s;
        }

        &-enter {
            opacity: 0;
            transform: translateY(15px);
        }

        &-leave-to {
            opacity: 0;
            transform: translateY(-15px);
        }
    }
</style>
