<template>
    <section class="app-header-container">
        <div class="app-header-container-top">
            <div class="container">
                <div class="row">
                    <div class="col col-12">
                        <div class="text-right">
                            <ul>
                                <li>
                                    <a href="#">Helper</a>
                                </li>
                                <li>
                                    <a href="#">Become Supplier</a>
                                </li>
                                <li>
                                    <a href="#">Language</a>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </div>
        <div class="app-header-container-main">
            <div class="container">
                <div class="row">
                    <div class="col col-3">
                        <router-link :to="{ name : 'Home'}" class="app-header-logo">
                            <img :src="`${$store.getters.baseUrl}/logo.png`" alt="">
                        </router-link>
                    </div>
                    <div class="col col-6">
                        <form-search></form-search>
                    </div>
                    <div class="col col-3">
                        <div class="app-header-seller">
                            <ul>
                                <li>
                                    <a href="#">
                                        Import list
                                    </a>
                                </li>
                                <li >
                                    <transition name="fade" mode="out-in">
                                        <div class="user-profile" v-if="isLogged" key="is-logged">
                                            <div class="dropdown" v-if="seller">
                                                <button class="user-info" type="button" data-toggle="dropdown">
                                                    <span class="user-media">
                                                        <img src="@/assets/images/default/avatar.png" alt="">
                                                    </span>
                                                    <span class="user-name">
                                                        {{seller.email}}
                                                    </span>
                                                </button>
                                                <div class="dropdown-menu dropdown-menu-right user-dropdown" >
                                                    <ul>
                                                        <li>
                                                            <router-link :to="{name : 'Seller'}">
                                                                Account Info
                                                            </router-link>
                                                        </li>
                                                        <li>
                                                            <a @click="logout()">Logout</a>
                                                        </li>
                                                    </ul>
                                                </div>
                                            </div>
                                        </div>
                                        <router-link :to="{name : 'Login' }"  v-else key="not-login">
                                            Login/Register
                                        </router-link>
                                    </transition>
                                </li>
                            </ul>
                        </div>
                    </div>
                </div>
            </div>
        </div>
    </section>
</template>
<script>
import FormSearch from './search'
import { mapGetters , mapActions } from 'vuex';
export default {
    name : 'Header',
    components:{
        FormSearch
    },
    computed :{
        ...mapGetters({
            isLogged : '$_Seller/isLoggedIn',
            seller : '$_Seller/getSeller',
            router : 'getRouter'
        })
    },
    methods:{
        ...mapActions({
            getUserInfo : '$_Seller/GET_USER_INFO'
        }),
        logout(){
            this.$store.dispatch('$_Seller/LOGOUT')
            $notify({
                content : 'Logout successfully',
                type : 'success'
            })
            if( this.router.matched.some(record => record.meta.requiresAuth) ){
                this.redirect({name : 'Login'})
            }
        }
    },
    watch :{
        'isLogged' : function(value){
            if( value == true){
                this.getUserInfo()
            }
        }
    },
    mounted(){
        if( this.isLogged  && this.seller == null ){
            this.getUserInfo()
        }
    }
}
</script>

<style lang="scss" scoped>
    @import 'src/assets/style';
    .app-header{
        &-container{
            background: $black;
            width: 100%;
            // min-height: 100px;
            color:#fff;
            &-top{
                width: 100%;
                min-height: 30px;
                background: $grey;
                ul{
                    padding: 0;
                    margin: 0;
                    li{
                        display: inline-block;
                        a{
                            display: inline-block;
                            padding: 6px 20px;
                            text-decoration: none;
                            color:#fff;
                            &:hover{
                                color:$yellow;
                            }
                        }
                    }
                }
            }
            &-main{
                background: transparent;
                width: 100%;
                padding: 15px 0;
            }
        }
        &-logo{
            display: inline-block;
            padding: 0px 15px;
            img{
                max-width: 100%;
                max-height: 60px;
            }
        }
        &-seller{
            text-align: right;
            padding-top: 20px;
            >ul{
                padding: 0;
                margin: 0;
                list-style-type: none;
                display: flex;
                align-items: center;
                justify-content: flex-end;
                >li{
                    display: inline-block;
                    margin-left: 10px;
                    max-width: 200px;
                    &:first-child{
                        margin-left: 0;
                    }
                    a{
                        display: inline-block;
                        color:#fff;
                        padding: 6px 15px;
                        &:hover{
                            color:$yellow;
                            text-decoration: none;
                        }
                    }
                    .user{
                        &-profile{

                        }
                        &-info{
                            display: flex;
                            flex-direction: row;
                            flex-wrap: nowrap;
                            align-items: center;
                            border-radius: 0;
                            border: none;
                            background: transparent;
                            color:#fff;
                            outline: none;
                            position: relative;
                            &:focus,&:visited{
                                outline: none;
                                box-shadow: none;
                            }
                            &:after{
                                content : '\f107';
                                @include fontawesome;
                                font-weight: 300;
                                margin-left: 3px;
                            }
                        }
                        &-media{
                            width: 30px;
                            height: 30px;
                            border-radius: 50%;
                            overflow: hidden;
                            margin-right: 5px;
                            display: inline-flex;
                            justify-content: center;
                            align-items: center;
                            img{
                                max-width: 100%;
                                max-height: 100%;
                            }
                        }
                        &-name{
                            max-width: 100px;
                            overflow: hidden;
                            text-overflow: ellipsis;
                            white-space: nowrap;
                        }
                        &-dropdown{
                            border-radius: 0;
                            box-shadow: 0px 5px 5px -3px rgba(0,0,0,0.2), 0px 8px 10px 1px rgba(0,0,0,0.14), 0px 3px 14px 2px rgba(0,0,0,0.12);
                            opacity: 0;
                            visibility: hidden;
                            transition: all 0.3s ease;
                            display: block;
                            right: 0 !important;
                            top: 100% !important;
                            left: auto !important;
                            transform: translateY(10px) !important;
                            &.show{
                                opacity: 1;
                                visibility: visible;
                                transform: none !important;
                            }
                            ul{
                                list-style-type: none;
                                padding: 0;
                                margin: 0;
                                li{
                                    display: block;
                                    margin: 0;
                                    a{
                                        display: block;
                                        padding: 6px 15px;
                                        color:$text-color;
                                        &:hover{
                                            background: $yellow;
                                            color:#fff;
                                        }
                                    }
                                }
                            }
                        }
                    }
                }
            }
        }
    }
</style>
